import axios from 'axios';

const api = axios.create({ baseURL: '/api' });

export const predictYield       = (data) => api.post('/predict',         data).then(r => r.data);
export const optimizeYield      = (data) => api.post('/optimize',        data).then(r => r.data);
export const getRecommendations = (data) => api.post('/recommendations', data).then(r => r.data);
export const getCrops           = ()     => api.get('/crops').then(r => r.data);
